INSERT INTO `cameras` VALUES (1,10,'Sony','2026-05-06 20:56:37.670796',500000,3999998,'Nâng tầm nghệ thuật chụp ảnh tĩnh và quay phim, máy ảnh α7 V chính là người bạn đồng hành hoàn hảo cho các nhà sáng tạo giàu ý tưởng. Được trang bị cảm biến hình ảnh và bộ xử lý nâng cao, khả năng nhận dạng chủ thể bằng AI tiên tiến, tính năng chụp liên tục không bị chớp đen tới 30 hình/giây14, cùng với dải tần nhạy sáng lên đến 16 stop16, chiếc máy ảnh này mang đến chất lượng hình ảnh chưa từng có.',1,NULL,'Máy ảnh Hybrid Full-Frame α7 V','may-anh-hybrid-full-frame-7-v','{\"Cảm biến hình ảnh Exmor RS™ CMOS xếp chồng một phần full-frame 33,0 triệu điểm ảnh11\":\"SỐ LƯỢNG ĐIỂM ẢNH (Tổng cộng) Xấp xỉ 35,7 triệu điểm ảnh\",\"BIONZ XR2 tích hợp bộ xử lý AI\":\"LOẠI CẢM BIẾN Full-frame 35 mm (35,9 x 23,9 mm), cảm biến Exmor RS CMOS\",\"Bộ xử lý AI tiên tiến giúp nhận dạng chủ thể chính xác đối với nhiều chủ thể khác nhau\":\"SỐ LƯỢNG ĐIỂM ẢNH (HIỆU DỤNG) Ảnh tĩnh: Xấp xỉ tối đa 33,0 triệu điểm ảnh64, Phim: Xấp xỉ tối đa 27,6 triệu điểm ảnh64\",\"Chụp liên tục không bị chớp đen lên đến 30 hình/giây với khả năng theo dõi lấy nét tự động/phơi sáng tự động toàn diện14\":\"ĐIỂM LẤY NÉT Ảnh tĩnh: Tối đa 759 điểm (lấy nét tự động theo pha), Phim: Tối đa 759 điểm (lấy nét tự động theo pha)\",\"Chống rung lên đến 7,5 bước24 ở giữa ảnh và 6,5 bước ở rìa ảnh để quay chụp cầm tay\":\"Thời lượng pin (Ảnh tĩnh) Xấp xỉ 630 lần chụp (Khung ngắm) / Xấp xỉ 750 lần chụp (Màn hình LCD) (Chuẩn CIPA)65\"}',10,'2026-05-19 22:08:39.676495',8,0,NULL,'active'),(2,28,'Sony','2026-05-06 23:20:18.942901',800000,9000000,'FX2 là chiếc máy quay full-frame thuộc dòng Cinema Line, kế thừa triết lý hình ảnh đỉnh cao từ dòng VENICE – biểu tượng điện ảnh hàng đầu của Sony. Với khả năng di động, thao tác và mở rộng vượt trội cùng độ tin cậy cao, máy quay này là lựa chọn lý tưởng để quay phim độc lập, đồng thời trang bị các chức năng ảnh tĩnh nâng cao hỗ trợ trọn vẹn quy trình làm phim hiện đại.',1,NULL,'Máy quay full-frame Cinema Line FX2','may-quay-full-frame-cinema-line-fx2','{\"Cảm biến Exmor R™ CMOS full-frame và bộ xử lý hình ảnh BIONZ XR™\":\"LOẠI CẢM BIẾN Full-frame 35 mm (35,9 x 23,9 mm), cảm biến Exmor R CMOS\",\"S-Log3 và ISO cơ sở kép để chỉnh màu chuyên nghiệp\":\"SỐ LƯỢNG ĐIỂM ẢNH (HIỆU DỤNG) Ảnh tĩnh: Xấp xỉ tối đa 33,0 triệu điểm ảnh51, Phim: Xấp xỉ tối đa 27,6 triệu điểm ảnh51\",\"Khả năng quay phim không gián đoạn36 lên đến 4K 60p50\":\"ĐỘ NHẠY ISO Ảnh tĩnh: ISO 100–51200 (có thể mở rộng lên ISO 50–204800), TỰ ĐỘNG (ISO 100–12800, có thể chọn giới hạn trên và giới hạn dưới), Phim: tương đương ISO 100–51200 (có thể mở rộng lên ISO 102400), TỰ ĐỘNG (ISO 100–12800, có thể chọn giới hạn trên và giới hạn dưới)\",\"Thân máy gọn nhẹ với khả năng mở rộng vượt trội, lý tưởng để quay phim độc lập\":\"ĐỘ NHẠY ISO Ảnh tĩnh: ISO 100–51200 (có thể mở rộng lên ISO 50–204800), TỰ ĐỘNG (ISO 100–12800, có thể chọn giới hạn trên và giới hạn dưới), Phim: tương đương ISO 100–51200 (có thể mở rộng lên ISO 102400), TỰ ĐỘNG (ISO 100–12800, có thể chọn giới hạn trên và giới hạn dưới)\",\"Thoải mái ghi hình với khung ngắm điện tử có thể điều chỉnh góc và BIG6 (Home) screen\":\"Khe cắm thẻ nhớ KHE CẮM 1: Khe cắm đa năng dành cho thẻ nhớ SD (tương thích UHS-I/II) / thẻ CFexpress 2 Type A, KHE CẮM 2: Thẻ nhớ SD (tương thích UHS-I/II)\"}',28,'2026-05-06 23:20:18.942901',NULL,0,NULL,'active'),(3,14,'Sony','2026-05-06 23:27:10.542191',8000000,5000000,'Máy quay FX3 thuộc Cinema Line có độ nhạy sáng cao và khả năng biểu đạt đậm chất điện ảnh ở chế độ full-frame, trong thiết kế gọn nhẹ đến không ngờ. Với khả năng di động tốt hơn giúp bạn dễ dàng thao tác độc lập, cùng các tính năng vận hành chuyên nghiệp, đây là công cụ sáng tạo lý tưởng để ghi lại cảnh phim đậm chất điện ảnh ở bất kỳ đâu.',1,NULL,'Máy quay full-frame FX3 thuộc Cinema Line','may-quay-full-frame-fx3-thuoc-cinema-line','{\"Hiệu suất full-frame với độ nhạy sáng cao và dải tần nhạy sáng rộng\":\"LOẠI CẢM BIẾN Full-frame 35 mm (35,6 x 23,8 mm), cảm biến Exmor R CMOS\",\"Bộ xử lý hình ảnh BIONZ XR hiệu suất cao\":\"Điểm ảnh Xấp xỉ 10,3 triệu điểm ảnh (hiệu dụng) để quay phim, Xấp xỉ 12,1 triệu điểm ảnh (hiệu dụng) để chụp Ảnh tĩnh, Xấp xỉ 12,9 triệu điểm ảnh (tổng cộng)\",\"Quay 4K (QFHD) ở tốc độ khung hình cao 120 hình/giây12\":\"ĐỘ NHẠY [Phim] Tương đương ISO 80-102400 (Có thể mở rộng lên ISO 409600), TỰ ĐỘNG (ISO 80-12800, có thể chọn giới hạn trên và giới hạn dưới), [Ảnh tĩnh] ISO 80-102400 (Có thể mở rộng lên ISO 40-409600), TỰ ĐỘNG (ISO 80-12800, có thể chọn giới hạn trên và giới hạn dưới)\",\"Công nghệ màu sắc điện ảnh với S-Cinetone™\":\"LOẠI PHƯƠNG TIỆN Thẻ CFexpress Type A/SD (x2), Quay đồng thời, Phân loại, Tự động chuyển phương tiện, Sao chép\",\"Khả năng di động nâng cao cho phép thao tác độc lập\":\"LCD Loại 7,5 cm (loại 3.0), xấp xỉ 2,36 triệu điểm, bảng cảm ứng, Góc mở: xấp xỉ 176 độ, Góc xoay: xấp xỉ 270 độ\"}',16,'2026-05-12 02:20:19.403454',NULL,0,NULL,'active'),(4,11,'Sony','2026-05-06 23:33:42.038134',2000000,500000,'α1 II là thế hệ thứ hai của máy ảnh ống kính rời không gương lật flagship α1 của Sony. Với khả năng nhận dạng chủ thể dựa trên AI tốt hơn, cùng độ phân giải và tốc độ cao của chiếc α1 nguyên bản, giờ đây bạn có thể bắt trọn hình ảnh với tỷ lệ thành công cao hơn, đồng thời tận hưởng quy trình làm việc chuyên nghiệp với sự tự do và độ hiệu quả vô song.',1,NULL,'Máy ảnh flagship α1 II dành cho chuyên gia','may-anh-flagship-1-ii-danh-cho-chuyen-gia','{\"Cảm biến hình ảnh Exmor RS CMOS xếp chồng full-frame 35 mm 50,1 triệu điểm ảnh19\":\"LOẠI CẢM BIẾN Full-frame 35 mm (35,9 x 24,0 mm), cảm biến Exmor RS CMOS\",\"Bộ xử lý hình ảnh BIONZ XR với cho phép bạn xem không bị chớp đen, cũng như theo dõi lấy nét tự động/phơi sáng toàn diện lên tới 30 hình/giây11\":\"SỐ LƯỢNG ĐIỂM ẢNH (HIỆU DỤNG) Ảnh tĩnh: Xấp xỉ tối đa 50,1 triệu điểm ảnh60, Phim: Xấp xỉ tối đa 42,0 triệu điểm ảnh\",\"Lấy nét tự động nhận dạng trong thời gian thực nhận dạng nhiều loại chủ thể khác nhau cho cả ảnh tĩnh và phim\":\"ĐIỂM LẤY NÉT Ảnh tĩnh: Tối đa 759 điểm (lấy nét tự động theo pha), Phim: Tối đa 759 điểm (lấy nét tự động theo pha)\",\"Hệ thống ổn định hình ảnh quang học 5 trục đạt hiệu quả 8,5 bước ở giữa ảnh / 7,0 bước ở rìa ảnh\":\"ĐỘ NHẠY ISO Ảnh tĩnh: ISO 100–32000 (có thể mở rộng đến ISO 50–102400), TỰ ĐỘNG (ISO 100–12800, có thể chọn giới hạn dưới và giới hạn trên), Phim: Tương đương ISO 100–32000, TỰ ĐỘNG (ISO 100–12800, có thể chọn giới hạn dưới và giới hạn trên)\",\"Khả năng quay phim lên đến 8K 30p và 4K 120p\":\"Khe cắm thẻ nhớ KHE CẮM 1: Khe cắm đa năng dành cho thẻ nhớ SD (tương thích UHS-I/II) / thẻ CFexpress 2.0 Type A, KHE CẮM 2: Khe cắm đa năng dành cho thẻ nhớ SD (tương thích UHS-I/II) / thẻ CFexpress 2.0 Type A. Loại màn hình TFT loại 8,0 cm (loại 3,2 inch)\"}',11,'2026-05-06 23:33:42.038134',NULL,0,NULL,'active'),(5,21,'Sony','2026-05-06 23:38:30.195222',1000000,999996,'- Cảm biến hình ảnh CMOS 24,6 MP2 xếp chồng full-frame với hệ thống màn trập bao trùm\n- Bộ xử lý hình ảnh BIONZ XR với sức mạnh xử lý cao hơn gấp 8 lần\n- Chụp không bị chớp đen ở tốc độ 120 hình/giây với tính năng theo dõi lấy nét tự động/phơi sáng tự động toàn diện\n- Tốc độ màn trập tối đa 1/80000 giây khi đồng bộ hóa flash\n- Nhận dạng đáng tin cậy nhiều loại chủ thể hơn',1,NULL,'α9 III với màn trập bao trùm','9-iii-voi-man-trap-bao-trum',NULL,21,'2026-05-06 23:38:30.195222',NULL,0,NULL,'active'),(6,0,'Sony','2026-05-06 23:43:04.943344',200000,50000,'- Quay phim chuẩn 4K vượt trội lên đến 60p/50p',1,NULL,'Máy ảnh full-frame nhỏ gọn α7CR 61,0 MP','may-anh-full-frame-nho-gon-7cr-610-mp',NULL,1,'2026-05-07 02:12:35.007764',NULL,0,NULL,'active'),(7,10,'Panasonic','2026-05-08 02:28:39.253508',400000,20000,'',1,NULL,'Máy ảnh Panasonic Lumix DC-TZ99 / ZS99 Trắng','may-anh-panasonic-lumix-dc-tz99-zs99-trang','{\"- Cảm biến MOS độ nhạy cao 20,3MP 1/2,3\\\"\":\"- Ống kính zoom 30x Leica DC Vario-Elmar\",\"- Màn hình cảm ứng nghiêng 3.0\\\" 1.84m-Dot\":\"- Khe cắm đơn SD/SDHC/SDXC\",\"- Phạm vi độ nhạy ISO 80 đến 3200 (Mở rộng 6400)\":\"- Bluetooth 5.0 tích hợp và Wi-Fi 2,4 GHz\"}',10,'2026-05-18 03:21:57.247484',8,0,NULL,'active'),(8,10,'Panasonic','2026-05-08 02:37:27.124238',90000,1000000,'',1,NULL,'Máy ảnh Panasonic Lumix GH7 Body','may-anh-panasonic-lumix-gh7-body','{\"- Thân máy bền bỉ, chịu được thời tiết\":\"- Khe cắm thẻ nhớ CFexpress Type B & SD UHS-II\",\"- Màn hình cảm ứng góc tự do 3,0\\\" 1,84 triệu điểm\":\"- Kính ngắm điện tử OLED 3,68 triệu điểm\",\"- Khả năng chống rung 7.5 stop\":\"- Tự động lấy nét theo pha cho hiệu suất chính xác, tốc độ cao\",\"- Video 5,7K 30p, 4K 120p và FHD 240p\":\"- Ghi nội bộ ProRes RAW HQ và ProRes 422 HQ\"}',10,'2026-05-18 03:21:28.171436',8,0,NULL,'active'),(9,10,'Panasonic','2026-05-08 03:03:29.164827',300000,200000,'Panasonic S1 II là máy ảnh mirrorless full-frame cao cấp, nổi bật với khả năng quay video chuyên nghiệp, cảm biến chất lượng cao, chống rung mạnh mẽ và hiệu suất lấy nét cải tiến, phù hợp cho cả nhiếp ảnh gia lẫn nhà sáng tạo nội dung.',1,NULL,'Máy ảnh Panasonic S1 II','may-anh-panasonic-s1-ii','{\"- V-Log và V-Gamut với dải động 13+ điểm dừng\":\"- C4K và UHD 4K 120p cho chuyển động chậm và hành động nhanh\",\"- Tự động lấy nét lai pha với 779 điểm lấy nét\":\"- Chụp liên tục 70 khung hình/giây không bị mất nét với AF liên tục (AFC)\",\"- Công nghệ IS 5 trục 8.0 dừng\":\"- Chế độ độ phân giải cao cho hình ảnh 96MP\"}',10,'2026-05-18 12:11:50.851932',6,0,NULL,'active'),(10,9,'Fujifilm','2026-05-08 03:13:20.998428',500000,400000,'',1,NULL,'Fujifilm X100VI - Màu Đen','fujifilm-x100vi-mau-den','{\"Trọng lượng: 521 Gram\":\"Kích thước: 128 * 75 * 55 mm\",\"Cảm biến APS-C 40.2MP X-Trans CMOS 5 HR BSI\":\"Bộ xử lý hình ảnh X-Processor 5\",\"Khung ngắm điện tử OLED EVF Hybrid 0.52x với 3.69 triệu điểm ảnh\":\"Ống kính Fujinon 23mm f/2\",\"Video 4K 60 fps 200Mbps, Full HD 120p 200Mbps\":\"Màn hình LCD cảm ứng nghiêng 3 inch với 1.62m-Dot, lật 90°\",\"ISO 160 – 12800, mở rộng xuống 50 và lên tới 51200\":\"Hệ thống lấy nét lai 425 điểm Hybrid AF, theo pha, tương phản\",\"Khoảng Focus gần nhất: 10cm\":\"Tốc độ chụp liên tiếp tối đa: 11 fps\",\"Tích hợp Wifi, Bluetooth\":\"Cổng kết nối: Type-C, Mic, Micro HDMI\",\"Kết nối với Smartphone qua FUJIFILM XApp 01 khe thẻ SD\":\"Pin sạc Lithium-ion NP-W126S chụp được 450 ảnh\"}',11,'2026-05-15 23:04:34.325653',NULL,0,NULL,'active'),(11,1,'Canon','2026-05-08 03:24:38.158307',10000,100000,'davve',1,NULL,'bửb','bub',NULL,1,'2026-05-18 01:24:38.888100',NULL,1,NULL,'active'),(12,10,'Canon','2026-05-09 02:07:36.200546',70000,5000,'jhcdacjudshvcqu',1,NULL,'avd','avd',NULL,10,'2026-05-18 01:25:10.366990',NULL,1,NULL,'active'),(13,2,'Panasonic','2026-05-09 02:08:59.553026',400,4000,'gvwr',1,NULL,'evsdgv','evsdgv',NULL,2,'2026-05-18 01:24:57.325805',NULL,1,NULL,'active'),(14,3,'Canon','2026-05-09 02:24:23.060012',88888,7779,'de',1,NULL,'ẻbftbebfs','ebftbebfs',NULL,3,'2026-05-18 01:24:05.104798',NULL,1,NULL,'active'),(15,2,'Panasonic','2026-05-09 02:25:07.026339',2,7,'dvfsvdv',1,NULL,'evwv','evwv',NULL,2,'2026-05-18 01:23:23.075629',NULL,1,NULL,'active'),(16,2,'Panasonic','2026-05-09 02:31:41.709719',100,100,'',1,NULL,'dvd','dvd',NULL,2,'2026-05-18 01:24:48.901503',NULL,1,NULL,'active'),(17,11,'Canon','2026-05-09 02:37:03.753434',20,12,'',1,NULL,'165','165',NULL,11,'2026-05-18 01:23:55.903136',NULL,1,NULL,'active'),(18,1,'Fujifilm','2026-05-09 02:37:41.680921',9,222,'',1,NULL,'515','515',NULL,1,'2026-05-18 01:23:39.507202',8,1,NULL,'active'),(19,13,'Fujifilm','2026-05-12 22:17:56.697442',200000,500000,'Fujifilm XF 23mm f/2.8 R WR là ống kính mirrorless siêu nhỏ gọn, nhưng không kém phần mạnh mẽ và sở hữu nhiều tính năng thông minh. Với trọng lượng chỉ 90g, nhưng ống kính lại mang trong mình khả năng lấy nét vượt trội, chất lượng hình ảnh có độ sắc nét cao và khả năng chống chịu thời tiết ấn tượng. Ống kính này gần như “vô hình” khi gắn lên các máy ảnh dòng X của Fujifilm, mang đến trải nghiệm nhiếp ảnh thuần túy và nhẹ nhàng cho người dùng.',1,NULL,'Ống kính Fujifilm XF 23mm f/2.8 R WR (Silver) | Chính hãng','ong-kinh-fujifilm-xf-23mm-f28-r-wr-silver-chinh-hang','{\"2 thấu kính phi cầu độ phân giải cao\":\"Cảm biến APS-C, khẩu độ f/2.8-f/16\",\"Hỗ trợ filter trước đường kính 39mm\":\"Khẩu độ 11 lá, bokeh mượt mà\"}',12,'2026-05-14 20:31:36.483647',12,0,NULL,'active'),(20,9,'Fujifilm','2026-05-12 22:24:13.505190',5000000,400000,'Ống kính zoom tele FUJIFILM XF 50-140mm f/2.8 R LM OIS WR được thiết kế chuyên để sử dụng trong các điều kiện thời tiết khắc nghiệt. Lens sở hữu những công nghệ tiên tiến cùng dải tiêu cự lý tưởng để chụp ảnh chân dung và ngoại cảnh, mang đến cho người dùng những trải nghiệm thú vị.',1,NULL,'Ống kính Fujifilm XF 50-140mm f/2.8 R LM OIS WR | Chính hãng','ong-kinh-fujifilm-xf-50-140mm-f28-r-lm-ois-wr-chinh-hang','{\"76-213mm (Tương đương 35mm)\":\"Năm phần tử ED & một phần tử Super ED\",\"Ống kính ngàm X / Định dạng APS-C\":\"Phạm vi khẩu độ: f / 2.8 đến f / 22\"}',10,'2026-05-16 11:13:15.558572',12,0,NULL,'active'),(21,13,'Fujifilm','2026-05-12 22:27:41.879012',600000,500000,'FUJIFILM XF 18-120mm f/4 R LM PZ WR thuộc dòng ống kính zoom vô cùng linh hoạt, thu phóng tiêu chuẩn được thiết kế cực kỳ phù hợp dành cho những người tạo nội dung và người làm hình ảnh chuyển động. FUJIFILM XF 18-120mm f/4 R LM PZ WR được trang bị dải độ dài tiêu cự linh hoạt, ngôn ngữ thiết kế trực quan, dễ dàng kiểm soát quá trình thu phóng, lấy nét, và điều chỉnh khẩu độ từ thân máy.',1,NULL,'Ống kính FUJIFILM XF 18-120mm f/4 LM PZ WR | Chính Hãng','ong-kinh-fujifilm-xf-18-120mm-f4-lm-pz-wr-chinh-hang','{\"27-183mm (tương đương 35mm)\":\"Chống chịu thời tiết và lớp phủ Flo mặn trước thấu kính\",\"Động cơ lấy nét tự động tuyến tính\":\"Các thấu kính phi cầu và ED\"}',14,'2026-05-15 03:58:59.916593',12,0,NULL,'active'),(22,12,'Panasonic','2026-05-12 22:35:11.445271',120000,119998,'Panasonic Lumix S Pro 50mm f/1.4 kết hợp giữa tốc độ và thấu kính ấn tượng, là ống kính prime tiêu cự thông thường dùng cho máy ảnh mirrorless ngàm L. Ống kính này trang bị khẩu độ lớn nhất f/1.4 nhanh, làm việc hiệu quả trong điều kiện thiếu sáng và cải thiện kiểm soát độ sâu trường ảnh để chụp tách chủ thể với hậu cảnh. Thiết kế quang học gồm 1 cặp thấu kính phi cầu kết hợp 3 thấu kính ED giúp giảm cầu sai và quang sai sắc, cho độ sắc nét và trong trẻo cao đạt được xuyên suốt dãy khẩu độ. \n\nThiết kế chống bụi và chịu được thời tiết khắc nghiệt\n\nPanasonic Lumix S Pro 50mm f1.4 được hãng trang bị đầy đủ khả năng chống chịu thời tiết trong môi trường có nhiệt độ xuống dưới – 10 độ C. Nhờ vậy, Panasonic Lumix S Pro 50mm f1.4 cho phép các nhiếp ảnh gia tác nghiệp dễ dàng trong môi trường mưa, gió nhưng vẫn đảm bảo chất lượng hình ảnh vượt trội.\n\nCấu tạo quang học\n\nPanasonic Lumix S Pro 50mm f1.4 có 13 thấu kính chia thành 11 nhóm, trong đó bao gồm 3 thấu kính tán xạ thấp ED và 2 thấu kính phi cầu. Với 3 thấu kính tán xạ thấp ED, Panasonic Lumix S Pro 50mm f1.4 giúp giảm viền màu, quang sai sắc cho hình ảnh có màu sắc tự nhiên cùng độ tương phản cao. Thêm vào đó, với 2 thấu kính phi cầu, ống kính hỗ trợ giảm thiểu méo hình và cầu sai trên toàn dãy zoom nhằm giữ nguyên độ sắc nét và độ sáng trên toàn khung hình.\n\nSở hữu khẩu độ tối đa f1.4, Panasonic Lumix S Pro 50mm f1.4 giúp người dùng sử dụng tốt trong điều kiện ánh sáng yếu, đặc biệt có thể kiểm soát vị trí lấy nét tốt hơn khi áp dụng các kỹ thuật chụp độ sâu trường nông.',1,NULL,'Ống Kính Lumix S Pro 50mm F1.4','ong-kinh-lumix-s-pro-50mm-f14','{\"-Ngàm L / Full frame\":\"– 11 lá khẩu tròn\",\"– Khẩu độ: f/1.4 – f/16\":\"– Gồm 3 thấu kính ED và 2 thấu kính phi cầu\",\"– Hệ thống AF kép\":\"– Thiết kế kháng thời tiết\"}',12,'2026-05-18 01:12:20.353973',12,0,NULL,'active'),(23,10,'Fujifilm','2026-05-12 22:40:48.382616',900000,600000,'',1,NULL,'Ống Kính Panasonic Lumix S PRO 70-200mm F/2.8 OIS (S-E70200)','ong-kinh-panasonic-lumix-s-pro-70-200mm-f28-ois-s-e70200','{\"– Tiêu cự: 70 đến 200mm\":\"– Khẩu độ tối đa: f/2.8\",\"– Khẩu độ tối thiểu: f/22\":\"– Góc nhìn: 4 ° đến 12 °\",\"– Độ phóng đại tối đa: 0,21x\":\"– Khoảng cách lấy nét tối thiểu: 95 cm\",\"– Kích thước bộ lọc: 82 mm (Mặt trước)\":\"– Kích thước: 94,4 x 208,6 mm\"}',11,'2026-05-14 20:30:44.454758',12,0,NULL,'active'),(24,11,'Panasonic','2026-05-12 22:48:13.356163',4500000,300000,'Ống kính Panasonic Leica DG Vario-Summilux 10-25mm f/1.7 ASPH là ống kính zoom có góc siêu rộng với khẩu độ F/1.7 đầu tiên trên thế giới.\nQuy đổi tiêu cự theo chuẩn Full-Frame, ống kính Leica DG Vario-Summilux 10-25mm f/1.7 ASPH cho góc nhìn tương đương với tiêu cự 20-50mm, rất phổ thông với người dùng chụp ảnh và quay phim. Vì đây là khẩu cứng f/1.7, nên hình thức bên ngoài của ống kính này hầm hố hơn hẳn so với nhiều ống kính khác thiết kế cho hệ Micro 4/3. Khi zoom, đầu ống kính sẽ thò thụt ra ngoài làm tăng chiều dài của ống kính.\nTrên thân ống có in đầy đủ vạch báo khoảng cách nét, tối thiểu từ 0,28m ra đến vô cực và nó là vòng nét cơ học, không phải dạng vòng nét điện tử (focus by wire). Ngoài ra, ống kính này còn  có  vòng khẩu cơ học với ký tự  “A” (chữ A màu đỏ) để ưu tiên chỉnh khẩu độ trên thân máy hoặc tự xoay vật lý ra các khẩu độ mình muốn. Số lá khẩu của ống kính Leica DG 10-25mm này là 9 lá khẩu, có mép gần tròn, hứa hẹn sẽ tạo ra những bức ảnh có bokeh tuyệt đẹp, rất đáng giá với các anh em thích chụp chân dung.\nGiống nhiều dòng cao cấp khác, ống kính Leica DG 10-25mm f/1.7  được trang bị thêm các vòng cao su tại các khe hở trên lớp vỏ bên ngoài, giảm thiểu nguy cơ lọt bụi, ẩm vào trong lòng ống. Điều này giúp gia tăng thêm khả năng chống chịu của ống kính trước các tác động từ môi trường bên ngoài như trời mưa lắc rắc hoặc gió cát.\n\nVề cấu trúc bên trong, theo thông tin của nhà sản xuất, nó  gồm 17 thấu kính chia trong 12 nhóm, sản xuất theo công nghệ của Leica. Trong 17 thấu kính, có 3 thấu kính phi cầu và 4 thấu kính tán xạ thấp, giúp gia tăng độ sắc nét, giảm thiểu hiện tượng tán sắc ánh sáng khi truyền từ không khí vào thấu kính. Với các nỗ lực nhằm tối ưu thiết kế, ống kính này vẫn cho chất lượng hình ảnh tốt mà kích thước vẫn khá vừa phải.',1,NULL,'Ống Kính Panasonic Leica DG Vario-Summilux 10-25mm F/1.7 ASPH (H-X1025)','ong-kinh-panasonic-leica-dg-vario-summilux-10-25mm-f17-asph-h-x1025','{\"– Tiêu cự: 10-25mm trên Micro 4/3, tương đương 20-50mm trên Fullframe\":\"– Số lá khẩu: 9\",\"– Khẩu độ tối đa: Một khẩu độ f/1.7, chỉnh khẩu độ từ f/1.7 đến f/16\":\"– Thấu kính đặc biệt: Phi cầu và tán sắc thấp\",\"– Lớp phủ thấu kính: UHR\":\"– Độ phóng đại tối đa: 0,14x\",\"– Khoảng AF gần nhất: 0,28m\":\"– Motor AF: motor bước STM\",\"– Khối lượng: 690g\":\"– Thước đo khoảng cách: in trên thân ống\",\"– Lens hood: Đi kèm trong hộp đựng\":\"– Filter: cỡ 77mm\",\"– Vỏ: hợp kim magie\":\"– Chống thời tiết: Có, chịu được tới -10 độ C\"}',13,'2026-05-16 12:36:27.818091',12,0,NULL,'active'),(25,20,'Canon','2026-05-16 03:39:21.621750',450000,400000,'Canon EOS R10 + Kit RF-S 18-45mm là mẫu máy ảnh mirrorless APS-C hiện đại, phù hợp cho người mới bắt đầu, bán chuyên và các nhà sáng tạo nội dung cần một thiết bị nhỏ gọn nhưng mạnh mẽ. Máy được trang bị cảm biến CMOS APS-C 24.2MP kết hợp bộ xử lý DIGIC X, mang lại chất lượng hình ảnh sắc nét, màu sắc chân thực và hiệu suất lấy nét nhanh với công nghệ Dual Pixel CMOS AF II thông minh. Canon EOS R10 hỗ trợ chụp liên tiếp tốc độ cao, quay video 4K UHD chất lượng tốt, rất phù hợp cho nhu cầu chụp du lịch, chân dung, vlog, sự kiện và quay video sáng tạo.\n\nPhiên bản đi kèm ống kính RF-S 18-45mm f/4.5-6.3 IS STM giúp người dùng dễ dàng sử dụng ngay với dải tiêu cự linh hoạt, hỗ trợ chụp phong cảnh, đời sống thường ngày và video cơ bản. Thiết kế thân máy gọn nhẹ, dễ mang theo, hỗ trợ kết nối WiFi/Bluetooth tiện lợi cho việc chia sẻ dữ liệu nhanh chóng.',1,NULL,'Canon EOS R10 + Kit RF-S 18-45mm','canon-eos-r10-kit-rf-s-18-45mm','{\"Định dạng: Canon RF Mount APS-C\":\"Cảm biến CMOS 24.2MP, vi xử lý DIGIC X\",\"Trọng lượng: 382.2 Gram\":\"Chip Dual Pixel CMOS AF II\",\"Video 4K30 10-Bit, HDR-PQ\":\"Chụp liên tiếp 23fps\",\"Chống rung kỹ thuật số (Chỉ Video)\":\"Hệ tiêu cự Crop: 1.6x\",\"ISO: 100 - 32.000 (Mở rộng : 100 - 51.200)\":\"Tốc độ màn trập: 1/4000 - 30 giây\",\"651 điểm lấy nét theo pha\":\"Màn hình LCD xoay lật cảm ứng 3 inch, 1,040,000 Dot\",\"Kính ngắm EVF OLED 2,360,000 Dot bao phủ 100% khung ngắm\":\"01 khe thẻ nhớ SD\",\"Kích thước: 122.5 * 87.8 * 83.4 mm\":\"Jack Video: Micro-HDMI, jack Audio 3.5mm\",\"Cổng kết nối Type-C\":\"Tích hợp Wireless, Bluetooth\"}',21,'2026-05-16 12:32:22.865108',6,0,5.00,'active'),(26,18,'Canon','2026-05-16 03:45:08.139698',500000,500000,'Canon EOS R8 + RF 24-105mm F4L là bộ máy ảnh mirrorless full-frame cao cấp, hướng đến người dùng bán chuyên, chuyên nghiệp và các nhà sáng tạo nội dung cần chất lượng hình ảnh vượt trội cùng hệ thống ống kính cao cấp. Canon EOS R8 sở hữu cảm biến CMOS full-frame 24.2MP kết hợp bộ xử lý DIGIC X mạnh mẽ, mang lại khả năng chụp ảnh sắc nét, dải tương phản rộng, hiệu suất ISO tốt trong điều kiện thiếu sáng và quay video 4K 60fps 10-bit chuyên nghiệp. Hệ thống lấy nét Dual Pixel CMOS AF II thông minh hỗ trợ nhận diện người, động vật và phương tiện với tốc độ nhanh, chính xác cao.\n\nĐi kèm là ống kính Canon RF 24-105mm f/4L IS USM thuộc dòng L cao cấp, nổi bật với khẩu độ cố định f/4, chất lượng quang học xuất sắc, khả năng chống rung hiệu quả và dải zoom đa dụng từ góc rộng đến tele ngắn. Combo này cực kỳ phù hợp cho chụp chân dung, sự kiện, du lịch, thương mại, quay video chuyên nghiệp và sáng tạo nội dung chất lượng cao.\n\nThiết kế tổng thể vừa gọn nhẹ hơn DSLR truyền thống nhưng vẫn đảm bảo hiệu suất mạnh mẽ, giúp Canon EOS R8 + RF 24-105mm F4L trở thành lựa chọn lý tưởng cho người dùng muốn bước vào hệ sinh thái full-frame RF với trải nghiệm cao cấp, linh hoạt và bền bỉ.',1,NULL,'Canon EOS R8 + RF 24-105mm F4L','canon-eos-r8-rf-24-105mm-f4l','{\"Định dạng : Canon RF Mount FullFrame\":\"Cảm biến CMOS 24.2MP, vi xử lý DIGIC X\",\"Video 4K60 10-Bit, HDR-PQ, Canon Log 3, HDR-PQ\":\"Chip Dual Pixel CMOS AF II\",\"Chụp liên tiếp 40fps (màn trập điện tử) tối đa 120 Frames JPEG\":\"Quay Video tối đa 2 giờ ở tốc độ 29.97 khung hình/giây\",\"Chống rung kỹ thuật số 5 trục (Chỉ Video)\":\"Tốc độ màn trập : 1/4000 - 30 giây\",\"ISO : 100 - 102,400 (Mở rộng : 50 - 204,800)\":\"Lấy nét tự động theo pha : Photo 4897, Video 4067\",\"Màn hình LCD xoay lật cảm ứng 3 inch, 1,620,000 Dot\":\"Kính ngắm OVF OLED 2,360,000 Dot bao phủ 100% khung ngắm\",\"01 khe thẻ nhớ SD\":\"Cổng kết nối Type-C\",\"Jack Video : Micro-HDMI, jack Audio 3.5mm\":\"Cổng kết nối Type-C\",\"Pin sạc Lithium-Ion LP-E17\":\"Tích hợp Wireless, Bluetooth\",\"Kích thước : 132.6 * 87 * 70.1 mm\":\"Trọng lượng : 414 Gram\"}',18,'2026-05-16 03:45:08.139698',6,0,5.00,'active'),(27,10,'Sony','2026-05-16 03:58:25.820495',800000,1000000,'Sony ZV-E10K / ZV-E10 Kit 16-50mm F3.5-5.6 OSS II là mẫu máy ảnh mirrorless APS-C chuyên vlog và sáng tạo nội dung, được Sony thiết kế tối ưu cho các vlogger, streamer, YouTuber và người dùng cần một thiết bị quay video chất lượng cao nhưng nhỏ gọn, dễ sử dụng. Máy sở hữu cảm biến APS-C Exmor CMOS 24.2MP kết hợp bộ xử lý BIONZ X, mang lại chất lượng hình ảnh sắc nét, màu sắc đẹp và hiệu suất lấy nét tự động nhanh với Real-time Eye AF cùng khả năng nhận diện chủ thể thông minh. Sony ZV-E10 hỗ trợ quay video 4K UHD, Full HD tốc độ cao, màn hình xoay lật hoàn toàn và microphone định hướng 3 capsule tích hợp, giúp tạo ra nội dung video chuyên nghiệp mà không cần quá nhiều phụ kiện ngoài.\n\nPhiên bản kit đi kèm ống kính Sony E PZ 16-50mm F3.5-5.6 OSS II mang lại sự linh hoạt cao cho nhu cầu quay vlog, chụp du lịch, chân dung và nội dung hàng ngày. Ống kính power zoom hỗ trợ zoom mượt khi quay video, đồng thời chống rung quang học OSS giúp hình ảnh ổn định hơn khi quay cầm tay. Thiết kế nhỏ nhẹ, hỗ trợ livestream, kết nối WiFi/Bluetooth và hệ sinh thái lens Sony E-mount phong phú giúp Sony ZV-E10 trở thành lựa chọn nổi bật trong phân khúc máy ảnh dành cho content creator. Đây là dòng máy đặc biệt phù hợp cho người mới bắt đầu làm nội dung hoặc cần thiết bị quay chụp đa năng với chi phí hợp lý.',1,NULL,'Máy ảnh Sony ZV-E10K / ZV-E10 Kit 16-50mm F3.5-5.6 OSS II','may-anh-sony-zv-e10k-zv-e10-kit-16-50mm-f35-56-oss-ii','{\"Cảm biến\":\"Exmor APS-C CMOS 24.2 Megapixels\",\"Bộ xử lý\":\"BIONZ X & trade\",\"Màn hình cảm ứng\":\"3.0 inch lật 180 độ\",\"Lấy nét tự động\":\"Fast Hybird\",\"Độ nhạy sáng\":\"ISO 100-32000 (mở rộng 51200)\",\"Tốc độ màn trập\":\"30 1/1400 giây\",\"Tốc độ chụp\":\"11 ảnh/ giây Quay phim\",\"Tích hợp\":\"Wifi/ NFC/ Bluetooth Pin tương thích\",\"Trọng lượng\":\"343g\"}',12,'2026-05-16 11:24:08.398272',9,0,5.00,'active'),(28,9,'Fujifilm','2026-05-16 04:15:15.323093',50000000,300000,'Fujifilm X-H2 + Tamron 17-70mm F/2.8 là bộ máy ảnh mirrorless APS-C cao cấp, hướng đến nhiếp ảnh gia bán chuyên, chuyên nghiệp và nhà sáng tạo nội dung cần hiệu suất mạnh mẽ cùng chất lượng hình ảnh vượt trội. Fujifilm X-H2 được trang bị cảm biến APS-C X-Trans CMOS 5 HR độ phân giải cao 40.2MP kết hợp bộ xử lý X-Processor 5, mang lại khả năng tái tạo chi tiết xuất sắc, màu sắc đặc trưng Fujifilm, hiệu suất lấy nét nhanh và hỗ trợ quay video 8K chuyên nghiệp. Máy sở hữu chống rung IBIS mạnh mẽ, thiết kế chắc chắn, phù hợp cho chụp ảnh thương mại, chân dung, phong cảnh, sự kiện và quay video cao cấp.\n\nĐi kèm là ống kính Tamron 17-70mm F/2.8 Di III-A VC RXD, nổi bật với khẩu độ lớn cố định F/2.8 trên toàn dải zoom, giúp chụp tốt trong điều kiện thiếu sáng, tạo bokeh đẹp và mang lại sự linh hoạt cao từ góc rộng đến chân dung. Ống kính này rất phù hợp cho du lịch, sự kiện, quay video và sử dụng đa mục đích, đồng thời tích hợp chống rung VC hỗ trợ quay/chụp ổn định hơn.\n\nTổng thể, Fujifilm X-H2 + Tamron 17-70mm F/2.8 là lựa chọn mạnh mẽ cho người dùng cần một hệ thống APS-C chuyên nghiệp với độ phân giải cao, hiệu năng toàn diện và chất lượng quang học xuất sắc.',1,NULL,'Fujifilm X-H2 + Tamron 17-70mm F/2.8','fujifilm-x-h2-tamron-17-70mm-f28','{\"Định dạng : FUJIFILM X-Mount\":\"Cảm biến : BSI 40.2MP CMOS APS-C X-Trans 5 HR\",\"Bộ xử lý hình ảnh : X-Processor 5\":\"Rung siêu âm làm sạch cảm biến\",\"Chống rung 5 trục trên thân máy đến 7 Stop\":\"Chụp đa điểm Pixel Shift 160MP\",\"Hỗ trợ ProRes 422 HQ and F-Log 2\":\"8K 30p, 4K 60p, FHD 240p 10-bit Video\",\"ISO : Photo 125 - 12,800 (Mở rộng 80 - 51,200);\":\"Video 160 - 12,800 (Mở rộng 160 - 25,600)\",\"Trọng lượng : 579 Gram\":\"Kích thước : 136.3 * 92.9 * 84.6 mm\",\"Kết nối Wi-Fi và Bluetooth\":\"Thiết kế chống chịu thời tiết\",\"Cổng kết nối : HDMI, 3.5mm, USB, Type-C, 2.5mm\":\"Khe thẻ 1: CFexpress Type B, Khe thẻ 2 : SD/SDHC/SDXC\",\"Chế độ giả nháy khi quay dưới đèn huỳnh quang\":\"Pin sạc Li-ion NP-W235, 7.2 VDC, 2200 mAh, Chụp : 680 tấm/1 lần sạc\",\"Chế độ mô phỏng điện ảnh Eterna\":\"Quay phim : DCI và UHD 8K tốc độ lên tới 200 Mbps, Chụp F-Log\",\"Thu âm thanh 24-bit\":\"Màn hình phụ LCD : 1.28\\\"\",\"425 điểm lấy nét theo pha\":\"Màn hình xoay lật cảm ứng LCD 3 inch 1,280,000 Dot\",\"EVF OLED 0.5\\\" 5,760,000 Dot,\":\"Thời lượng quay : 90\"}',9,'2026-05-18 14:41:58.813018',6,0,5.00,'active'),(29,1,'Nikon','2026-05-16 04:22:40.861199',500000,599996,'Nikon Z8 là mẫu máy ảnh mirrorless full-frame cao cấp chuyên nghiệp, được xem như phiên bản nhỏ gọn hơn của Nikon Z9 nhưng vẫn sở hữu hiệu năng mạnh mẽ hàng đầu, phù hợp cho nhiếp ảnh gia chuyên nghiệp, quay phim cao cấp, thương mại, thể thao, sự kiện và sáng tạo nội dung chuyên sâu. Máy sử dụng cảm biến stacked CMOS full-frame 45.7MP kết hợp bộ xử lý EXPEED 7, cho khả năng chụp tốc độ cực cao, lấy nét AI thông minh vượt trội và chất lượng hình ảnh xuất sắc với độ chi tiết cao, dải tương phản rộng cùng hiệu suất mạnh trong môi trường ánh sáng phức tạp.\n\nNikon Z8 hỗ trợ quay video chuyên nghiệp lên tới 8K, ProRes, N-RAW cùng hệ thống autofocus nhận diện chủ thể tiên tiến, đáp ứng tốt cả nhu cầu nhiếp ảnh lẫn điện ảnh chuyên nghiệp. Thiết kế thân máy chắc chắn, bền bỉ, chống chịu thời tiết tốt nhưng vẫn nhỏ gọn hơn DSLR flagship truyền thống, giúp tăng tính linh hoạt khi tác nghiệp thực tế.\n\nĐây là lựa chọn lý tưởng cho người dùng cần một hệ thống mirrorless full-frame mạnh mẽ, toàn diện, hiệu suất cao và đủ sức đáp ứng gần như mọi nhu cầu sáng tạo hình ảnh chuyên nghiệp.',1,NULL,'Nikon Z8','nikon-z8','{\"Trọng lượng: 820 Gram\":\"Kích thước: 144 * 118.5 * 83 mm\",\"Tích hợp Wifi, Bluetooth\":\"Jack cắm: HDMI Output, 3.5mm, Type-C input, USB-C Data Output, Nikon 10-Pin Control Input\",\"Pin sạc Lithium-ion EN-EL15C 7 VDC, 2280 mAh\":\"01 khe CFexpress Type B / XQD, 01 khe SD/SDHC/SDXC\",\"Màn hình cảm ứng LCD 3.2inch 4 trục nghiêng 2,100,000 Dot\":\"Kính ngắm Real Live, không blackout, 0.5 inch 3,690,000 Dot\",\"Định dạng: Nikon Z-Mount FullFrame\":\"​​​​​Cảm biến ảnh FX Format Stacked CMOS 45.7MP\",\"Pixel Shift: Dịch chuyển pixel ảnh 8-16 để có được tấm ảnh 200 MP+\":\"ISO gốc: 64-25.600 (Mở rộng 32 - 102,400)\",\"Lấy nét tự động 493 điểm, nhận diện đối tượng dựa trên AI\":\"Hybrid AF (AF tương phản + theo pha)\",\"Video 8.3K 60p N-RAW, 4.1K 60p ProRes RAW\":\"Video 8K30p & 4K120p, quay 10bit trong máy\",\"Chụp liên tiếp đến 20 fps Raw, đến 30 fps JPEG\":\"Chống rung IBIS 5 trục trong thân máy\"}',1,'2026-05-19 22:06:17.559524',6,0,5.00,'active'),(30,16,'Canon','2026-05-16 13:55:07.460762',5000,2000,'',1,NULL,'abc','abc',NULL,20,'2026-05-19 21:56:27.429546',5,0,5.00,'active'),(31,1,'Nikon','2026-05-16 22:09:50.885283',30000,200000,'Nikon Zf là máy ảnh mirrorless full-frame cao cấp mang phong cách retro cổ điển, sở hữu cảm biến 24.5MP, chống rung 5 trục, lấy nét AI mạnh mẽ và khả năng quay 4K, phù hợp cho chụp chân dung, du lịch, street photography và sáng tạo nội dung chuyên nghiệp.',1,NULL,'Nikon Zf','nikon-zf','{\"- Cảm biến ảnh FX BSI CMOS 24.5MP\":\"- Trọng lượng: 630g (Body only)\",\"- 2 khe đọc thẻ microSD / SD UHS-II\":\"- Chụp liên tục đến 30 fps, ISO mở rộng 50-204800\",\"- Chế độ chụp độ phân giải cao 96MP\":\"- Màn hình cảm ứng đa góc 3.2\\\" 2.1M điểm\",\"- Ổn định điểm lấy nét\":\"- Ổn định hình ảnh Vibration Reduction 5 trục 8 stop\"}',1,'2026-05-19 22:03:58.719579',6,0,5.00,'active'),(32,1,'Nikon','2026-05-17 14:18:23.492632',1000,19994,'',1,NULL,'Nikon Zf01','nikon-zf01',NULL,1,'2026-05-18 01:21:55.275184',5,1,5.00,'active'),(33,13,'Nikon','2026-05-17 14:20:34.474808',10000,10000,'',1,NULL,'Nikon JF 02','nikon-jf-02',NULL,14,'2026-05-18 01:22:01.808664',6,1,5.00,'active');
